def _toposolid_pierce_advisory_violations(
    elements: dict[str, Element],
) -> list[Violation]:
    """TOP-V3-01: warn when a slab footprint overlaps a toposolid boundary without excavation.

    Fires a non-blocking warning for each floor/slab whose XY footprint overlaps
    any toposolid boundary when no ``slab_opening`` or excavation is recorded
    for that overlap pair.
    """
    toposolids = [e for e in elements.values() if isinstance(e, ToposolidElem)]
    if not toposolids:
        return []

    floors = [e for e in elements.values() if isinstance(e, FloorElem)]
    if not floors:
        return []

    slab_opening_host_ids = {
        e.host_floor_id
        for e in elements.values()
        if isinstance(e, SlabOpeningElem)
    }

    out: list[Violation] = []
    for topo in toposolids:
        topo_poly = Poly(
            tuple((pt.x_mm, pt.y_mm) for pt in topo.boundary_mm)
        )
        for floor in floors:
            if floor.id in slab_opening_host_ids:
                continue
            if len(floor.boundary_mm) < 3:
                continue
            floor_poly = Poly(
                tuple((pt.x_mm, pt.y_mm) for pt in floor.boundary_mm)
            )
            if sat_overlap(topo_poly, floor_poly):
                out.append(
                    Violation(
                        rule_id="toposolid_pierce_check",
                        severity="warning",
                        message=(
                            f"Floor '{getattr(floor, 'name', floor.id)}' ({floor.id}) overlaps "
                            f"toposolid '{getattr(topo, 'name', topo.id) or topo.id}' ({topo.id}) "
                            "without a recorded slab_opening or excavation. "
                            "Add a slab_opening or excavation to model the basement cut."
                        ),
                        element_ids=[floor.id, topo.id],
                        blocking=False,
                    )
                )
    return out

